-		return s[:maxLen]
+		// Find last rune boundary at or before maxLen bytes
+		lastValid := 0
+		for i := range s {
+			if i > maxLen {
+				break
+			}
+			lastValid = i
+		}
+		if lastValid == 0 && len(s) > 0 {
+			// First rune is larger than maxLen, return empty
+			return ""
+		}
+		return s[:lastValid]
+	}
+	// Find first rune boundary at or after maxLen-3 bytes
+	targetLen := maxLen - 3
+	for i := range s {
+		if i >= targetLen {
+			return s[:i] + "..."
+		}
 	}
-	return s[:maxLen-3] + "..."
+	return s
 }

